  1	import * as React from 'react';
  2	import { getValidatedProp } from '@odf/shared/utils';
  3	import { TFunction } from 'react-i18next';
  4	import {
  5	  InputGroup,
  6	  FormGroup,
  7	  TextInput,
  8	  Button,
  9	  ValidatedOptions,
 10	  Tooltip,
 11	  InputGroupItem,
 12	  FormHelperText,
 13	  HelperText,
 14	  HelperTextItem,
 15	} from '@patternfly/react-core';
 16	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 17	import { VaultConfig } from '../../types';
 18	
 19	export const VaultTokenConfigure: React.FC<VaultAuthMethodProps> = ({
 20	  t,
 21	  className,
 22	  vaultState,
 23	  setAuthValue,
 24	  isScEncryption,
 25	}) => {
 26	  const [revealToken, setRevealToken] = React.useState(false);
 27	  const getValidatedAuthValueProp = getValidatedProp(
 28	    !vaultState.authValue?.valid
 29	  );
 30	
 31	  return (
 32	    <FormGroup
 33	      fieldId="vault-token"
 34	      label={t('Token')}
 35	      className={className}
 36	      isRequired
 37	    >
 38	      <InputGroup className="ocs-install-kms__form-token">
 39	        <InputGroupItem isFill>
 40	          <TextInput
 41	            value={vaultState.authValue?.value}
 42	            onChange={(_event, authValue: string) => setAuthValue(authValue)}
 43	            type={revealToken ? 'text' : 'password'}
 44	            id="vault-token"
 45	            name="vault-token"
 46	            isRequired
 47	            validated={getValidatedAuthValueProp}
 48	          />
 49	        </InputGroupItem>
 50	        <InputGroupItem>
 51	          <Tooltip
 52	            content={
 53	              revealToken
 54	                ? t('plugin__odf-console~Hide token')
 55	                : t('plugin__odf-console~Reveal token')
 56	            }
 57	          >
 58	            <Button
 59	              variant="control"
 60	              onClick={() => setRevealToken(!revealToken)}
 61	            >
 62	              {revealToken ? <EyeSlashIcon /> : <EyeIcon />}
 63	            </Button>
 64	          </Tooltip>
 65	        </InputGroupItem>
 66	      </InputGroup>
 67	      <FormHelperText>
 68	        <HelperText>
 69	          <HelperTextItem variant={getValidatedAuthValueProp}>
 70	            {getValidatedAuthValueProp === ValidatedOptions.default
 71	              ? isScEncryption &&
 72	                t(
 73	                  'Create a secret with the token for every namespace using encrypted PVCs.'
 74	                )
 75	              : t('This is a required field')}
 76	          </HelperTextItem>
 77	        </HelperText>
 78	      </FormHelperText>
 79	    </FormGroup>
 80	  );
 81	};
 82	
 83	export const VaultServiceAccountConfigure: React.FC<VaultAuthMethodProps> = ({
 84	  t,
 85	  className,
 86	  vaultState,
 87	  setAuthValue,
 88	}) => {
 89	  const getValidatedAuthValueProp = getValidatedProp(
 90	    !vaultState.authValue?.valid
 91	  );
 92	  return (
 93	    <FormGroup
 94	      fieldId="vault-sa-role"
 95	      label={t('plugin__odf-console~Role')}
 96	      className={className}
 97	      isRequired
 98	    >
 99	      <TextInput
100	        value={vaultState.authValue?.value}
101	        onChange={(_event, authValue: string) => setAuthValue(authValue)}
102	        type="text"
103	        id="vault-sa-role"
104	        name="vault-sa-role"
105	        isRequired
106	        validated={getValidatedAuthValueProp}
107	      />
108	      <FormHelperText>
109	        <HelperText>
110	          <HelperTextItem variant={getValidatedAuthValueProp}>
111	            {getValidatedAuthValueProp === ValidatedOptions.error &&
112	              t('This is a required field')}
113	          </HelperTextItem>
114	        </HelperText>
115	      </FormHelperText>
116	    </FormGroup>
117	  );
118	};
119	
120	export type VaultAuthMethodProps = {
121	  isScEncryption?: boolean;
122	  className: string;
123	  vaultState: VaultConfig;
124	  t: TFunction;
125	  setAuthValue: (string) => void;
126	};

